        while (x) {
            x &= x - 1; // Clear the least significant bit
            count++;
        }
        return count;
    }

    // Function to calculate the popcount-depth of a number
    function popcountDepth(x: number): number {
        let depth = 0;
        while (x !== 1) {
            x = popcount(x);
            depth++;
        }
        return depth;
