        return 0;
    }

    // Use BFS to find all numbers with popcount-depth exactly k
    let queue: number[] = [];
    let visited: Set<number> = new Set();

    // Start with all numbers from 1 to n that have popcount 1 (depth 1)
    for (let i = 1; i <= n; i++) {
        if (popcount(i) === 1) {
            queue.push(i);
            visited.add(i);
        }
    }

